const body = $('Webhook').first().json.body || $('Webhook').first().json;
const me = {
  session_id: String(body.session_id || ''),
  final_P: Number(body.final_P),
  final_A: Number(body.final_A),
  final_D: Number(body.final_D),
  match_mode: (String(body.match_mode || 'echo').toLowerCase().trim() === 'healing') ? 'healing' : 'echo',
  city: String(body.city || ''),
  lat: Number(body.lat),
  lng: Number(body.lng)
};
if (!me.session_id) throw new Error('session_id required');

const rows = $input.all().map(i => i.json);
const now = Date.now();
const THIRTY_MIN = 30 * 60 * 1000;
const FRESH_MS = 30 * 60 * 1000;  // candidates must have INTAKED within last 30 min

function isEligible(r) {
  if (String(r.session_id) === me.session_id) return false;

  // Recency: the candidate row itself must be fresh (last 30 min).
  // Demo rows bypass this because they're seeded standing partners.
  const isDemo = String(r.session_id).startsWith('demo_');
  const ts = r.timestamp ? Date.parse(r.timestamp) : 0;
  if (!isDemo) {
    if (!ts) return false;
    if ((now - ts) > FRESH_MS) return false;
  }

  const theirMode = (String(r.match_mode || 'echo').toLowerCase().trim() === 'healing') ? 'healing' : 'echo';
  if (theirMode !== me.match_mode) return false;

  if (me.match_mode === 'healing') {
    if (Number(r.final_D) === me.final_D) return false;
  } else {
    if (Number(r.final_D) !== me.final_D) return false;
  }

  const matched = String(r.matched_user_id || '').trim();
  const ended = String(r.match_ended_at || '').trim();
  if (!matched) return true;
  if (ended) return true;
  const mt = r.match_timestamp ? Date.parse(r.match_timestamp) : 0;
  if (mt && (now - mt) > THIRTY_MIN) return true;
  return false;
}

const candidates = rows.filter(isEligible).map(r => ({
  session_id: String(r.session_id),
  final_P: Number(r.final_P),
  final_A: Number(r.final_A),
  final_D: Number(r.final_D),
  match_mode: (String(r.match_mode || 'echo').toLowerCase().trim() === 'healing') ? 'healing' : 'echo',
  city: String(r.city || ''),
  lat: Number(r.lat),
  lng: Number(r.lng),
  timestamp: r.timestamp ? Date.parse(r.timestamp) : 0,
  dist: Math.sqrt(Math.pow(me.final_P - Number(r.final_P), 2) + Math.pow(me.final_A - Number(r.final_A), 2))
}));

const realCands = candidates.filter(c => !String(c.session_id).startsWith('demo_'));
const demoCands = candidates.filter(c =>  String(c.session_id).startsWith('demo_'));
const pool = realCands.length > 0 ? realCands : demoCands;
pool.sort((x, y) => (x.dist - y.dist) || (x.timestamp - y.timestamp));

const partner = pool[0];
const match_timestamp = new Date().toISOString();
const match_pair_id = partner ? [me.session_id, partner.session_id].sort().join('__') : '';

return [{
  json: {
    me,
    partner: partner || null,
    matched: !!partner,
    match_timestamp,
    match_pair_id,
    match_mode: me.match_mode
  }
}];

const match = $('Pick Partner').first().json;
const me = match.me || {};
const you = match.partner || {};
const mode = match.match_mode || 'echo';

function quadrant(P, A) {
  const p = Number(P), a = Number(A);
  if (p >= 0 && a >= 0) return 'joy';
  if (p >= 0 && a < 0)  return 'calm';
  if (p < 0  && a >= 0) return 'anxious';
  return 'melancholy';
}

const q = quadrant(me.final_P, me.final_A);

const bank = {
  echo: {
    joy:        ["something in the air tonight, yeah?","feels like a good kind of tired. how's yours?","today was loud in a good way. you?"],
    calm:       ["it's quiet here. how is it where you are?","no rush. just glad we landed in the same place.","soft evening. what does yours sound like?"],
    anxious:    ["my chest has been humming all day. has yours?","rough one, huh. you doing okay?","glad you showed up. what's been loud for you?"],
    melancholy: ["heavy day on my side. you too?","some days just drag. what's yours been like?","tired in the bones kind of tired. you?"]
  },
  healing: {
    joy:        ["there's someone listening. tell me about the best thing today.","i'm here with open ears, whatever you'd like to share.","start wherever you want. i'm not going anywhere."],
    calm:       ["take your time. i'll be here.","no need to warm up. start from the middle if you want.","i'm listening. what's been sitting with you?"],
    anxious:    ["you can set it down here, if you want. i'm just here.","whatever's been loud today, say it out loud. i'm listening.","no pressure to make sense. i'll follow."],
    melancholy: ["i'm here. however slow is fine.","you don't have to explain. just start somewhere.","tell me what today felt like. i'll stay."]
  }
};

const pool = (bank[mode] && bank[mode][q]) || bank.echo.calm;
const opener = pool[Math.floor(Math.random() * pool.length)];

return [{ json: {
  matched: true,
  partner_session_id: you.session_id,
  match_timestamp: match.match_timestamp,
  match_pair_id: match.match_pair_id,
  match_mode: mode,
  opener,
  me:      { city: me.city || '',  lat: me.lat  || null, lng: me.lng  || null, final_P: me.final_P,  final_A: me.final_A,  final_D: me.final_D },
  partner: { city: you.city || '', lat: you.lat || null, lng: you.lng || null, final_P: you.final_P, final_A: you.final_A, final_D: you.final_D }
} }];

const me = $('Pick Partner').first().json.me || {};
const mode = me.match_mode || 'echo';
const message = mode === 'healing'
  ? 'no one has opened themselves to a healing meeting yet. stay a moment.'
  : 'you are the first one here right now. please wait.';
return [{ json: { matched: false, match_mode: mode, message } }];
